using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service = new();

    private static List<OrderItem> CreateSampleItems() =>
    [
        new OrderItem { ProductName = "Widget", Price = 10.00m, Quantity = 2 },
        new OrderItem { ProductName = "Gadget", Price = 25.50m, Quantity = 1 }
    ];

    [TestClass]
    public sealed class CreateOrder
    {
        private readonly OrderService _service = new();

        [TestMethod]
        public void ReturnsOrder_WithCorrectCustomerId()
        {
            var order = _service.CreateOrder("cust-1", CreateSampleItems());

            Assert.AreEqual("cust-1", order.CustomerId);
        }

        [TestMethod]
        public void ReturnsOrder_WithAssignedId()
        {
            var order = _service.CreateOrder("cust-1", CreateSampleItems());

            Assert.IsFalse(string.IsNullOrEmpty(order.Id));
        }

        [TestMethod]
        public void ReturnsOrder_WithCorrectTotal()
        {
            var items = new List<OrderItem>
            {
                new() { ProductName = "A", Price = 10.00m, Quantity = 2 },
                new() { ProductName = "B", Price = 5.00m, Quantity = 3 }
            };

            var order = _service.CreateOrder("cust-1", items);

            // (10 * 2) + (5 * 3) = 35
            Assert.AreEqual(35.00m, order.Total);
        }

        [TestMethod]
        public void ReturnsOrder_WithUtcCreatedAt()
        {
            var before = DateTime.UtcNow;
            var order = _service.CreateOrder("cust-1", CreateSampleItems());
            var after = DateTime.UtcNow;

            Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
        }

        [TestMethod]
        public void ReturnsOrder_WithSameItems()
        {
            var items = CreateSampleItems();

            var order = _service.CreateOrder("cust-1", items);

            CollectionAssert.AreEqual(items, order.Items);
        }

        [TestMethod]
        public void ThrowsArgumentNullException_WhenCustomerIdIsNull()
        {
            Assert.ThrowsExactly<ArgumentNullException>(
                () => _service.CreateOrder(null!, CreateSampleItems()));
        }

        [TestMethod]
        public void ThrowsArgumentNullException_WhenItemsIsNull()
        {
            Assert.ThrowsExactly<ArgumentNullException>(
                () => _service.CreateOrder("cust-1", null!));
        }

        [TestMethod]
        public void ThrowsInvalidOperationException_WhenItemsIsEmpty()
        {
            Assert.ThrowsExactly<InvalidOperationException>(
                () => _service.CreateOrder("cust-1", []));
        }
    }

    [TestClass]
    public sealed class GetOrder
    {
        private readonly OrderService _service = new();

        [TestMethod]
        public void ReturnsOrder_WhenOrderExists()
        {
            var created = _service.CreateOrder("cust-1", CreateSampleItems());

            var retrieved = _service.GetOrder(created.Id);

            Assert.IsNotNull(retrieved);
            Assert.AreEqual(created.Id, retrieved.Id);
        }

        [TestMethod]
        public void ReturnsNull_WhenOrderDoesNotExist()
